"""Thin Qwen chat client with retry and strict response validation.

设计目标：
1) 统一从环境变量/密钥文件读取配置；
2) 对网络抖动和 5xx/429 做有限次重试；
3) 仅返回可用文本，异常统一抛 `QwenClientError`。
"""
# 模块说明：Qwen 对话客户端，负责请求、重试与响应校验。

from __future__ import annotations

import asyncio
import logging
import os
from pathlib import Path
from typing import Any, Mapping

import httpx


QWEN_CHAT_COMPLETIONS_URL = "https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions"
DEFAULT_QWEN_MODEL = "qwen-plus"
DEFAULT_QWEN_API_KEY_FILE = "config/apikey.txt"
DEFAULT_QWEN_TIMEOUT_SECONDS = 60.0
DEFAULT_QWEN_MAX_RETRIES = 2

LOGGER = logging.getLogger(__name__)


class QwenClientError(RuntimeError):
    """Raised when Qwen invocation cannot be completed safely."""


class QwenClient:
    def __init__(
        self,
        *,
        api_key: str | None,
        model: str = DEFAULT_QWEN_MODEL,
        endpoint: str = QWEN_CHAT_COMPLETIONS_URL,
        timeout_seconds: float = DEFAULT_QWEN_TIMEOUT_SECONDS,
        max_retries: int = DEFAULT_QWEN_MAX_RETRIES,
        http_client: httpx.AsyncClient | None = None,
        key_file: str = DEFAULT_QWEN_API_KEY_FILE,
    ) -> None:
        self._api_key = api_key.strip() if isinstance(api_key, str) and api_key.strip() else None
        self._model = model.strip() if model.strip() else DEFAULT_QWEN_MODEL
        self._endpoint = endpoint
        self._timeout_seconds = timeout_seconds
        self._max_retries = max(0, int(max_retries))
        self._http_client = http_client
        self._key_file = key_file

    @classmethod
    def from_env(
        cls,
        *,
        env: Mapping[str, str] | None = None,
        http_client: httpx.AsyncClient | None = None,
    ) -> "QwenClient":
        # 支持环境变量直传密钥，也支持从本地文件加载（便于本地调试）。
        source = os.environ if env is None else env
        key = str(source.get("QWEN_API_KEY", "")).strip()
        key_file = str(source.get("QWEN_API_KEY_FILE", DEFAULT_QWEN_API_KEY_FILE)).strip()
        model = str(source.get("QWEN_MODEL", DEFAULT_QWEN_MODEL)).strip() or DEFAULT_QWEN_MODEL
        timeout_seconds = _parse_float(
            source.get("QWEN_TIMEOUT_SECONDS"),
            default=DEFAULT_QWEN_TIMEOUT_SECONDS,
            minimum=1.0,
        )
        max_retries = _parse_int(
            source.get("QWEN_MAX_RETRIES"),
            default=DEFAULT_QWEN_MAX_RETRIES,
            minimum=0,
        )

        if not key:
            # 只有环境变量里没有明确提供密钥时，才回退到本地文件，避免覆盖线上注入的配置。
            key = cls._read_api_key_from_file(key_file)

        return cls(
            api_key=key or None,
            model=model,
            timeout_seconds=timeout_seconds,
            max_retries=max_retries,
            http_client=http_client,
            key_file=key_file or DEFAULT_QWEN_API_KEY_FILE,
        )

    @property
    def available(self) -> bool:
        return bool(self._api_key)

    @property
    def model(self) -> str:
        return self._model

    async def chat(self, *, messages: list[dict[str, str]], temperature: float = 0.2) -> str:
        if not self.available:
            raise QwenClientError(
                "Qwen API key is not configured. Set QWEN_API_KEY or provide QWEN_API_KEY_FILE."
            )

        # 保持 OpenAI-compatible 载荷格式，便于上层 prompt 组装逻辑与其他兼容模型共用调用方式。
        payload: dict[str, Any] = {
            "model": self._model,
            "messages": messages,
            "temperature": temperature,
        }

        response = await self._post(payload)
        return self._parse_content(response)

    async def _post(self, payload: dict[str, Any]) -> httpx.Response:
        # 若未注入外部 http client，则按调用周期创建并释放临时 client。
        headers = {
            "Authorization": f"Bearer {self._api_key}",
            "Content-Type": "application/json",
        }
        close_client = False
        client = self._http_client
        if client is None:
            client = httpx.AsyncClient(timeout=self._timeout_seconds)
            close_client = True

        try:
            for attempt in range(self._max_retries + 1):
                try:
                    response = await client.post(
                        self._endpoint,
                        headers=headers,
                        json=payload,
                    )
                    response.raise_for_status()
                    # 这里只确认 HTTP 成功；响应体是否合法由 `_parse_content` 继续校验。
                    return response
                except httpx.TimeoutException as exc:
                    # 超时走指数退避重试；超过阈值后明确失败。
                    if attempt < self._max_retries:
                        LOGGER.warning(
                            "qwen_request_timeout_retry attempt=%s max_retries=%s",
                            attempt + 1,
                            self._max_retries,
                        )
                        await asyncio.sleep(_retry_backoff_seconds(attempt))
                        continue
                    raise QwenClientError("Qwen request timed out") from exc
                except httpx.HTTPStatusError as exc:
                    status_code = exc.response.status_code
                    # 限流/服务端错误可重试，其他状态码直接失败。
                    if status_code in {429, 500, 502, 503, 504} and attempt < self._max_retries:
                        LOGGER.warning(
                            "qwen_request_http_retry status=%s attempt=%s max_retries=%s",
                            status_code,
                            attempt + 1,
                            self._max_retries,
                        )
                        await asyncio.sleep(_retry_backoff_seconds(attempt))
                        continue
                    detail = _response_text(exc.response)
                    raise QwenClientError(
                        f"Qwen API returned HTTP {status_code}: {detail}"
                    ) from exc
                except httpx.HTTPError as exc:
                    # 传输层异常也允许有限次重试，覆盖连接抖动、TLS 错误等瞬时问题。
                    if attempt < self._max_retries:
                        LOGGER.warning(
                            "qwen_request_transport_retry attempt=%s max_retries=%s error=%s",
                            attempt + 1,
                            self._max_retries,
                            str(exc),
                        )
                        await asyncio.sleep(_retry_backoff_seconds(attempt))
                        continue
                    raise QwenClientError(f"Qwen transport error: {exc}") from exc
            raise QwenClientError("Qwen request failed after retries")
        finally:
            if close_client:
                await client.aclose()

    @staticmethod
    def _parse_content(response: httpx.Response) -> str:
        # 仅接受 OpenAI-compatible 响应中的 choices[0].message.content。
        try:
            payload = response.json()
        except ValueError as exc:
            raise QwenClientError("Qwen API returned invalid JSON") from exc

        try:
            content = payload["choices"][0]["message"]["content"]
        except (KeyError, IndexError, TypeError) as exc:
            raise QwenClientError("Qwen API response missing choices[0].message.content") from exc

        if not isinstance(content, str):
            raise QwenClientError("Qwen API response content is not a string")

        text = content.strip()
        # 空字符串不能算有效回答，否则上层会误以为模型已经成功给出结果。
        if not text:
            raise QwenClientError("Qwen API response content is empty")
        return text

    @staticmethod
    def _read_api_key_from_file(path_value: str) -> str:
        # 相对路径既尝试当前工作目录，也尝试项目根目录，兼容不同启动方式。
        resolved = path_value.strip() or DEFAULT_QWEN_API_KEY_FILE
        candidates = [Path(resolved)]
        if not Path(resolved).is_absolute():
            project_root = Path(__file__).resolve().parent.parent
            candidates.append(project_root / resolved)

        for path in candidates:
            if not path.exists() or not path.is_file():
                continue
            try:
                # 文件读取失败直接尝试下一个候选路径，不把本地文件问题升级成启动错误。
                content = path.read_text(encoding="utf-8").strip()
            except OSError:
                continue
            if content:
                return content
        return ""


def _response_text(response: httpx.Response) -> str:
    # 优先返回原始文本；空响应体时再回退到 JSON 字符串，便于拼装错误详情。
    # 从 HTTP 响应里提取可读文本，供错误信息和调试日志复用。
    text = response.text.strip()
    if text:
        return text

    try:
        payload = response.json()
    except ValueError:
        return "empty response body"
    return str(payload)


def _parse_float(raw_value: Any, *, default: float, minimum: float) -> float:
    # timeout 这类配置来自环境变量时容易写错，这里统一做解析兜底和最小值保护。
    # 把原始浮点配置解析成合法范围内的值。
    try:
        parsed = float(raw_value)
    except (TypeError, ValueError):
        return default
    return max(parsed, minimum)


def _parse_int(raw_value: Any, *, default: int, minimum: int) -> int:
    # 重试次数等整型配置同样需要兜底，避免负数或非法值直接进入运行时。
    # 把原始整数配置解析成合法范围内的值。
    try:
        parsed = int(raw_value)
    except (TypeError, ValueError):
        return default
    return max(parsed, minimum)


def _retry_backoff_seconds(attempt: int) -> float:
    # 指数退避同时做上限截断，避免异常链路长时间阻塞整个请求。

