GATEWAY_CONTEXT_HEADER = "x-ai-biz-context"
LEGACY_HEADER_USER = "x-user-id"
LEGACY_HEADER_TENANT_DEPT = "x-tenant-dept-id"
AUTH_BYPASS_PATHS = {
