@dataclass(frozen=True)
class AuthContext:
    dept_id: str
    user_id: str
    trace_id: str = ""
    claims: dict[str, Any] | None = None

    def to_conversation_owner(self) -> ConversationOwner:
        return ConversationOwner(dept_id=self.dept_id, user_id=self.user_id)

    def conversation_context(self) -> dict[str, Any] | None:
        if not isinstance(self.claims, dict):
            return None
        context = self.claims.get("conversationContext")
        if isinstance(context, dict):
            return context
        return None


@dataclass(frozen=True)
class GatewayAuthSettings:
    internal_token: str
    context_sign_secret: str
    clock_skew_seconds: int = 30
    allow_legacy_headers: bool = False

    @classmethod
    def from_env(cls) -> "GatewayAuthSettings":
        # 兼容多种布尔写法，减少部署参数在不同环境里语义不一致的问题。
        token = os.getenv("AI_GATEWAY_INTERNAL_TOKEN", "").strip()
        secret = os.getenv("AI_GATEWAY_CONTEXT_SIGN_SECRET", "").strip()
        allow_legacy = os.getenv("AI_ALLOW_LEGACY_AUTH", "false").strip().lower() in {
            "1",
            "true",
            "yes",
            "on",
        }
        skew_raw = os.getenv("AI_GATEWAY_CLOCK_SKEW_SECONDS", "30").strip()
        try:
            skew = int(skew_raw)
        except ValueError:
            # 配置填错时回退到安全默认值，避免整个鉴权中间件直接不可用。
            skew = 30
        if skew < 0:
            skew = 0
        return cls(
            internal_token=token,
            context_sign_secret=secret,
            clock_skew_seconds=skew,
            allow_legacy_headers=allow_legacy,
        )


class GatewayAuthMiddleware(BaseHTTPMiddleware):
    def __init__(self, app, settings: GatewayAuthSettings | None = None) -> None:  # type: ignore[no-untyped-def]
        super().__init__(app)
        self._settings = settings or GatewayAuthSettings.from_env()

    async def dispatch(self, request: Request, call_next):
        path = request.url.path
        # 静态页面与健康探针默认免鉴权，避免影响调试与运维探活。
        if path in AUTH_BYPASS_PATHS or any(
            path == prefix or path.startswith(f"{prefix}/")
            for prefix in AUTH_BYPASS_PREFIXES
        ):
            return await call_next(request)

        try:
            # 鉴权错误统一在中间件出口转成 401，后续路由不再接触“半认证”请求。
            context = self._authenticate(request)
        except ValueError as exc:
            return JSONResponse(
                status_code=401,
                content={"detail": str(exc)},
            )

        request.state.auth_context = context
        return await call_next(request)

    def _authenticate(self, request: Request) -> AuthContext:
        token = (request.headers.get(GATEWAY_TOKEN_HEADER) or "").strip()
        signed_context = (request.headers.get(GATEWAY_CONTEXT_HEADER) or "").strip()
        if token and signed_context:
            settings = self._settings
            # 配置缺失属于部署错误，优先给出明确报错，避免误判成普通 token 不匹配。
            if not settings.internal_token:
                raise ValueError("gateway auth misconfigured: AI_GATEWAY_INTERNAL_TOKEN is empty")
            if not settings.context_sign_secret:
                raise ValueError("gateway auth misconfigured: AI_GATEWAY_CONTEXT_SIGN_SECRET is empty")
            if token != settings.internal_token:
                raise ValueError("invalid gateway internal token")
            # context 同时承担身份与租户范围，必须通过签名+时效校验。
            payload = _decode_signed_context(
                signed_context,
                secret=settings.context_sign_secret,
                clock_skew_seconds=settings.clock_skew_seconds,
            )
            # conversation 链路只认 tenantDeptId；tenantId 仅保留给审计和兼容映射。
            user_id = str(payload.get("userId", "")).strip()
            dept_id = str(payload.get("tenantDeptId") or payload.get("tenantId") or "").strip()
            if not user_id or not dept_id:
                raise ValueError("invalid gateway context: missing userId/tenantDeptId")
            trace_id = str(payload.get("traceId", "")).strip()
            return AuthContext(
                dept_id=dept_id,
                user_id=user_id,
                trace_id=trace_id,
                claims=payload,
            )

        if self._settings.allow_legacy_headers:
            # 旧 Header 没有签名能力，只允许在显式开关打开时作为兼容通道存在。
            user_id = (request.headers.get(LEGACY_HEADER_USER) or "").strip()
            dept_id = (request.headers.get(LEGACY_HEADER_TENANT_DEPT) or "").strip()
            if user_id and dept_id:
                return AuthContext(dept_id=dept_id, user_id=user_id)

        raise ValueError(
            "missing auth headers: require X-AI-GW-TOKEN and X-AI-BIZ-CONTEXT"
