def get_auth_context(request: Request) -> AuthContext:
    context = getattr(request.state, "auth_context", None)
    if context is None:
        # 正常链路一定会先经过鉴权中间件；这里兜底是为了防止路由被误接到未鉴权入口。
        raise HTTPException(status_code=401, detail="unauthenticated")
    return context


def _decode_signed_context(value: str, *, secret: str, clock_skew_seconds: int) -> dict[str, Any]:
    """解析并验证网关签名上下文（格式、签名、exp/iat 时钟窗口）。"""
    parts = value.split(".")
    if len(parts) != 3 or parts[0] != "v1":
        raise ValueError("invalid gateway context format")

    payload_b64 = parts[1]
    signature_b64 = parts[2]
    expected_signature = _hmac_sha256_base64url(secret, payload_b64)
    # 使用恒时比较，避免签名校验被时间侧信道利用。
    if not hmac.compare_digest(signature_b64, expected_signature):
        raise ValueError("invalid gateway context signature")

    payload_bytes = _b64url_decode(payload_b64)
    try:
        payload = json.loads(payload_bytes.decode("utf-8"))
    except Exception as exc:  # noqa: BLE001
        raise ValueError("invalid gateway context payload") from exc
    if not isinstance(payload, dict):
        raise ValueError("invalid gateway context payload")

    now = int(time.time())
    exp = _to_int(payload.get("exp"))
    iat = _to_int(payload.get("iat"))
    # 允许轻微时钟偏差，避免 Java 网关和 Python 服务时间有几秒差就全部拒绝。
    if exp is not None and now - clock_skew_seconds > exp:
        raise ValueError("gateway context expired")
    if iat is not None and iat - clock_skew_seconds > now:
        raise ValueError("gateway context iat is in the future")
    return payload


def _hmac_sha256_base64url(secret: str, payload: str) -> str:
    # 按网关约定生成 base64url 签名，和 Java 侧保持同一算法。
    digest = hmac.new(
        secret.encode("utf-8"),
        payload.encode("utf-8"),
        hashlib.sha256,
    ).digest()
    return base64.urlsafe_b64encode(digest).decode("utf-8").rstrip("=")


def _b64url_decode(value: str) -> bytes:
    # base64url 在传输时通常会省略 padding，解码前先补齐。
    padding = "=" * (-len(value) % 4)
    return base64.urlsafe_b64decode(value + padding)


def _to_int(value: Any) -> int | None:
    if value is None:
        return None
    if isinstance(value, bool):
        # bool 是 int 的子类，但这里不应被当作合法时间戳或数值字段。
        return None
    try:
        return int(value)
    except (TypeError, ValueError):
        return None

