import json
import re
from typing import Any, Literal


Action = Literal["CALL_TOOL", "CLARIFY", "RESPOND"]

_PLAN_JSON_BLOCK_PATTERN = re.compile(r"```(?:json)?\\s*(\{.*?\})\\s*```", re.DOTALL | re.IGNORECASE)


def normalize_action(value: Any) -> Action:
    # planner 只允许三种动作；未知值统一降级成 RESPOND，避免脏数据把图编排带偏。
    raw = clean_text(value).upper()
    if raw in {"CALL_TOOL", "CLARIFY", "RESPOND"}:
        return raw  # type: ignore[return-value]
    return "RESPOND"


def parse_json_payload(raw: str) -> dict[str, Any]:
    # 优先按完整 JSON 解析；失败后再尝试从 markdown code block 中恢复结构化载荷。
    text = raw.strip()
    try:
        payload = json.loads(text)
    except json.JSONDecodeError:
        match = _PLAN_JSON_BLOCK_PATTERN.search(text)
        if match is None:
            return {}
        try:
            # 只恢复第一个 JSON 代码块，避免把解释文本混进结构化输出。
            payload = json.loads(match.group(1))
